import{_ as e,c as t,a as l,o as a}from"./app-CEcM0piI.js";const n={};function o(r,i){return a(),t("div",null,i[0]||(i[0]=[l('<p>一般来说，对于数据库操作都是在访问数据库的时候创建连接，访问完毕断开连接。但是如果在高并发情况下，有些需要频繁处理的操作就会消耗很多的资源和时间，比如：</p><ul><li>建立通信连接的TCP三次握手</li><li>数据库服务器的连接认证</li><li>数据库服务器关闭连接时的资源回收</li><li>断开通信连接的TCP四次挥手</li><li>如果使用数据库连接池会减少这一部分的性能损耗。</li></ul><h4 id="设计" tabindex="-1"><a class="header-anchor" href="#设计"><span>设计</span></a></h4><p>要实现以下功能:</p><ol><li>连接池只需要一个实例，所以连接池类应该是一个单例模式的类</li><li>所有的数据库连接应该维护到一个安全的队列中 使用队列的目的是方便连接的添加和删除 所谓的安全指的是线程安全，也就是说需要使用互斥锁来保护队列数据的读写。</li><li>在需要的时候可以从连接池中得到一个或多个可用的数据库连接 如果有可用连接，直接取出 如果没有可用连接，阻塞等待一定时长然后再重试</li><li>如果队列中没有多余的可用连接，需要动态的创建新连接</li><li>如果队列中空闲的连接太多，需要动态的销毁一部分</li><li>数据库操作完毕，需要将连接归还到连接池中</li></ol>',5)]))}const m=e(n,[["render",o]]),c=JSON.parse('{"path":"/tools/mysql/5/","title":"5 数据库连接池","lang":"zh-CN","frontmatter":{"title":"5 数据库连接池","createTime":"2025/04/05 12:12:26","permalink":"/tools/mysql/5/"},"readingTime":{"minutes":1.32,"words":397},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/MySQL/5 数据库连接池.md","headers":[]}');export{m as comp,c as data};
